mapper.select:
SELECT 
	homepage_id, survey_idx, quest_idx, quest_type, quest_content, quest_auth, 
	quest_count, quest_detail_free_yn, quest_order, matrix_count, 
	add_date, add_user_id, required_yn
FROM
	CMS_SURVEY_QUEST
WHERE
	quest_idx = #{quest_idx}
AND	survey_idx = #{survey_idx}
AND	homepage_id = #{homepage_id}

mapper.update:
UPDATE CMS_SURVEY_QUEST SET 
	quest_content = #{quest_content}, 
	quest_auth = NVL(#{quest_auth}, 'ALL'), 
	quest_count = #{quest_count}, 
	matrix_count = #{matrix_count},
	quest_detail_free_yn = #{quest_detail_free_yn},
	required_yn = #{required_yn},
	modify_date = SYSDATE,
	modify_user_id = #{modify_user_id}
WHERE
	quest_idx = #{quest_idx}
AND	survey_idx = #{survey_idx}
AND homepage_id = #{homepage_id}

mapper.delete:
DELETE CMS_SURVEY_QUEST 
WHERE
	survey_idx = #{survey_idx}
AND	quest_idx = #{quest_idx}
AND homepage_id = #{homepage_id}

mapper.update:
UPDATE
	CMS_SURVEY_QUEST
SET
	quest_order = quest_order - 1,
	modify_date = SYSDATE,
	modify_user_id = #{modify_user_id}
WHERE
	survey_idx = #{survey_idx}
AND	homepage_id = #{homepage_id}
AND	quest_order > #{quest_order}
